struct Solution { black_map: std::collections::HashMap<i32, i32>, black_rows: i32, black_cols: i32, black_size: i32 }
impl Solution { fn new(m: i32, n: i32) -> Self { Self { black_map: std::collections::HashMap::new(), black_rows: m, black_cols: n, black_size: m * n } } fn flip(&mut self) -> Vec<i32> { self.black_size -= 1; let black_r = (rand::random::<u32>() % (self.black_size + 1) as u32) as i32; let black_idx = *self.black_map.get(&black_r).unwrap_or(&black_r); self.black_map.insert(black_r, *self.black_map.get(&self.black_size).unwrap_or(&self.black_size)); vec![black_idx / self.black_cols, black_idx % self.black_cols] } fn reset(&mut self) { self.black_map.clear(); self.black_size = self.black_rows * self.black_cols; } }